@Post('tickets/:id/confirm')
async confirmTicket(@Param('id') ticketId: string, @CurrentUser() user) {
  const ticket = await this.ticketRepo.findOneBy({ id: ticketId });
  // BUG: không kiểm tra ticket.status có đúng là 'matched' trước khi confirm —
  // gọi thẳng API này trên ticket đang 'queued' hoặc đã 'cancelled' vẫn chạy qua
  ticket.status = 'confirmed';
  await this.ticketRepo.save(ticket);
  return ticket;
}
